logger = logging.getLogger()
logger.setLevel(os.getenv("LOG_LEVEL", "INFO"))

s3 = boto3.client("s3")
sns = boto3.client("sns")

OUTPUT_BUCKET = os.getenv("OUTPUT_BUCKET")
OUTPUT_PREFIX = os.getenv("OUTPUT_PREFIX", "processed/")
SNS_TOPIC_ARN = os.getenv("SNS_TOPIC_ARN")


def lambda_handler(event, context):
    logger.info("Received event: %s", json.dumps(event))

    results = []

    records = event.get("Records", [])
    if not records:
        logger.warning("No records found in event")
        return {
            "statusCode": 400,
            "body": json.dumps({"message": "No records found"})
        }

    for record in records:
        try:
            result = process_record(record, context)
            results.append({"success": True, "result": result})
        except Exception as e:
            logger.error("Failed to process record: %s", str(e))
            logger.error(traceback.format_exc())
            results.append({"success": False, "error": str(e)})

    return {
        "statusCode": 200,
        "body": json.dumps({"results": results})
    }


def process_record(record, context):
    bucket = record["s3"]["bucket"]["name"]
    key = unquote_plus(record["s3"]["object"]["key"])

    logger.info("Processing image from bucket=%s key=%s", bucket, key)

    image_bytes = read_from_s3(bucket, key)
    processed_bytes = process_image(image_bytes, bucket, key)

    destination_bucket = OUTPUT_BUCKET or bucket
    destination_key = build_output_key(key)

    write_to_s3(destination_bucket, destination_key, processed_bytes)

    notification = {
        "source_bucket": bucket,
        "source_key": key,
        "destination_bucket": destination_bucket,
        "destination_key": destination_key,
        "status": "processed",
        "request_id": getattr(context, "aws_request_id", None)
    }

    send_sns_notification(notification)

    logger.info(
        "Successfully processed image source=%s/%s destination=%s/%s",
        bucket,
        key,
        destination_bucket,
        destination_key
    )

    return notification


def read_from_s3(bucket, key):
    try:
        response = s3.get_object(Bucket=bucket, Key=key)
        data = response["Body"].read()
        logger.info("Read %d bytes from s3://%s/%s", len(data), bucket, key)
        return data
    except ClientError as e:
        logger.error("Error reading from S3: %s", str(e))
        raise


def write_to_s3(bucket, key, data):
    try:
        s3.put_object(
            Bucket=bucket,
            Key=key,
            Body=data,
            ContentType=guess_content_type(key)
        )
        logger.info("Wrote %d bytes to s3://%s/%s", len(data), bucket, key)
    except ClientError as e:
        logger.error("Error writing to S3: %s", str(e))
        raise


def send_sns_notification(message):
    if not SNS_TOPIC_ARN:
        logger.warning("SNS_TOPIC_ARN not configured; skipping notification")
        return

    try:
        sns.publish(
            TopicArn=SNS_TOPIC_ARN,
            Subject="Image Processing Complete",
            Message=json.dumps(message)
        )
        logger.info("Published SNS notification to %s", SNS_TOPIC_ARN)
    except ClientError as e:
        logger.error("Error publishing to SNS: %s", str(e))
        raise


def process_image(image_bytes, bucket, key):
    logger.info("Performing placeholder image processing for s3://%s/%s", bucket, key)
    return image_bytes


def build_output_key(source_key):
    filename = source_key.split("/")[-1]
    return f"{OUTPUT_PREFIX}{filename}"


def guess_content_type(key):
    lower_key = key.lower()
    if lower_key.endswith(".jpg") or lower_key.endswith(".jpeg"):
        return "image/jpeg"
    if lower_key.endswith(".png"):
        return "image/png"
    if lower_key.endswith(".gif"):
        return "image/gif"
    if lower_key.endswith(".webp"):
        return "image/webp"
    if lower_key.endswith(".bmp"):
        return "image/bmp"
    if lower_key.endswith(".tiff") or lower_key.endswith(".tif"):
        return "image/tiff"
    return "application/octet-stream"